# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, session, jsonify
from werkzeug.security import generate_password_hash
from functools import wraps
import re

app = Flask(__name__)
app.secret_key = "replace_with_real_secret_key"

# Dummy in-memory "database"
users = {
    1: {
        "email": "user@example.com",
        "password_hash": generate_password_hash("oldpassword"),
        "two_factor_enabled": False,
    }
}

def login_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if "user_id" not in session or session["user_id"] not in users:
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return wrapper

def valid_email(email: str) -> bool:
    return bool(re.match(r"[^@]+@[^@]+\.[^@]+", email))

@app.route("/api/profile", methods=["POST"])
@login_required
def update_profile():
    data = request.get_json(silent=True) or {}
    user = users[session["user_id"]]

    if "email" in data:
        if not valid_email(data["email"]):
            return jsonify({"error": "Invalid email"}), 400
        user["email"] = data["email"]

    if "password" in data:
        if len(data["password"]) < 8:
            return jsonify({"error": "Password too short"}), 400
        user["password_hash"] = generate_password_hash(data["password"])

    if "two_factor_enabled" in data:
        user["two_factor_enabled"] = bool(data["two_factor_enabled"])

    return jsonify({
        "email": user["email"],
        "two_factor_enabled": user["two_factor_enabled"]
    }), 200

# Example login route for testing purposes
@app.route("/login", methods=["POST"])
def login():
    session["user_id"] = 1
    return "", 204

if __name__ == "__main__":
    app.run(debug=True)